import { Component, inject, signal, computed, effect, OnInit, ChangeDetectionStrategy } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { CodeValueService, MPageService, MpageSelectComponent, PrsnlService } from '@clinicaloffice/mpage-developer';
import { ConfigurationService } from '../../services/configuration.service';
import { AccessControlService } from '../../services/access-control.service';
import { AccessControlConfig, ALL_TABS, OncSchedConfiguration } from '../../models/schedule.model';

@Component({
  selector: 'app-security',
  standalone: true,
  imports: [FormsModule, MpageSelectComponent],
  templateUrl: './security.html',
  styleUrl: './security.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class SecurityComponent implements OnInit {
  private readonly codeValueService = inject(CodeValueService);
  private readonly configService = inject(ConfigurationService);
  readonly accessControl = inject(AccessControlService);
  private readonly mPage = inject(MPageService);
  private readonly prsnlService: any = inject(PrsnlService);

  readonly saving = signal(false);
  readonly positionsLoaded = signal(false);
  readonly statusMessage = signal<string | null>(null);
  private statusTimer: ReturnType<typeof setTimeout> | null = null;

  readonly newPosition = signal('');

  readonly allPositions = signal<{ codeValue: number; display: string }[]>([]);
  readonly editableConfig = signal<AccessControlConfig | null>(null);

  /** Personnel lookup signals */
  readonly selectedPersonnelId = signal<number>(0);
  readonly lookupResult = signal<{ name: string; position: string; added: boolean; alreadyExists: boolean } | null>(null);
  readonly lookupLoading = signal(false);

  readonly tabs = ALL_TABS;

  private readonly configEffect = effect(() => {
    const config = this.configService.configuration()?.ACCESS_CONTROL;
    if (config) {
      this.editableConfig.set(JSON.parse(JSON.stringify(config)));
    }
  });

  readonly configuredPositions = computed((): string[] => {
    const config = this.editableConfig();
    if (!config) return [];
    const positions = new Set<string>(config.superusers);
    for (const tab of Object.values(config.tabs)) {
      for (const pos of tab.positions) {
        positions.add(pos);
      }
    }
    return Array.from(positions).sort();
  });

  readonly hasUnsavedChanges = computed(() => {
    const editable = this.editableConfig();
    const saved = this.configService.configuration()?.ACCESS_CONTROL;
    if (!editable || !saved) return editable !== null;
    return JSON.stringify(editable) !== JSON.stringify(saved);
  });

  ngOnInit(): void {
    const existing = this.codeValueService.getCodeSet(88);
    if (existing?.length) {
      this.applyPositions(existing);
    }
    this.codeValueService.load(88, 0, '', '', '', false, () => {
      this.applyPositions(this.codeValueService.getCodeSet(88));
    });
  }

  private applyPositions(cvs: any[]): void {
    const values = cvs
      .map(cv => ({ codeValue: cv.codeValue, display: cv.display }))
      .sort((a, b) => a.display.localeCompare(b.display));
    this.allPositions.set(values);
    this.positionsLoaded.set(true);
  }

  isSuperuser(position: string): boolean {
    return this.editableConfig()?.superusers.includes(position) ?? false;
  }

  toggleSuperuser(position: string): void {
    this.editableConfig.update(config => {
      if (!config) return config;
      const updated = { ...config, superusers: [...config.superusers] };
      if (updated.superusers.includes(position)) {
        updated.superusers = updated.superusers.filter(p => p !== position);
      } else {
        updated.superusers.push(position);
      }
      return updated;
    });
  }

  hasTabAccess(position: string, tabKey: string): boolean {
    const config = this.editableConfig();
    return config?.tabs[tabKey]?.positions.includes(position) ?? false;
  }

  toggleTabAccess(position: string, tabKey: string): void {
    this.editableConfig.update(config => {
      if (!config) return config;
      const updated = { ...config, tabs: { ...config.tabs } };
      if (!updated.tabs[tabKey]) {
        const tabDef = ALL_TABS.find(t => t.key === tabKey);
        updated.tabs[tabKey] = { label: tabDef?.label ?? tabKey, positions: [] };
      }
      const tab = { ...updated.tabs[tabKey], positions: [...updated.tabs[tabKey].positions] };
      if (tab.positions.includes(position)) {
        tab.positions = tab.positions.filter(p => p !== position);
      } else {
        tab.positions.push(position);
      }
      updated.tabs[tabKey] = tab;
      return updated;
    });
  }

  addPosition(): void {
    const pos = this.newPosition().trim();
    if (!pos) return;
    if (this.configuredPositions().includes(pos)) return;

    this.editableConfig.update(config => {
      if (!config) return config;
      const updated = { ...config, tabs: { ...config.tabs } };
      if (!updated.tabs['schedule']) {
        updated.tabs['schedule'] = { label: 'Schedule', positions: [pos] };
      } else {
        const tab = { ...updated.tabs['schedule'], positions: [...updated.tabs['schedule'].positions, pos] };
        updated.tabs['schedule'] = tab;
      }
      return updated;
    });
    this.newPosition.set('');
  }

  removePosition(position: string): void {
    this.editableConfig.update(config => {
      if (!config) return config;
      const updated = {
        superusers: config.superusers.filter(p => p !== position),
        tabs: { ...config.tabs }
      };
      for (const [key, tab] of Object.entries(updated.tabs)) {
        updated.tabs[key] = { ...tab, positions: tab.positions.filter(p => p !== position) };
      }
      return updated;
    });
  }

  onPositionSelect(event: Event): void {
    this.newPosition.set((event.target as HTMLSelectElement).value);
  }

  /**
   * Handle personnel selection from mpage-select.
   * Loads prsnl data to get position, then auto-adds to matrix if new.
   */
  onPersonnelSelected(): void {
    const personId = this.selectedPersonnelId();
    if (!personId || personId === 0) return;

    this.lookupLoading.set(true);
    this.lookupResult.set(null);

    this.prsnlService.load('PRSNL_MIN', [{ personId }]);

    const startTime = Date.now();
    const check = () => {
      if (Date.now() - startTime > 10000) {
        this.lookupLoading.set(false);
        this.lookupResult.set({ name: 'Unknown', position: 'Lookup timed out', added: false, alreadyExists: false });
        return;
      }
      if (this.prsnlService.has(personId)) {
        const prsnl = this.prsnlService.get(personId);
        this.lookupLoading.set(false);

        if (!prsnl || !prsnl.position) {
          this.lookupResult.set({
            name: prsnl?.nameFullFormatted ?? 'Unknown',
            position: '(No position assigned)',
            added: false,
            alreadyExists: false
          });
          return;
        }

        const position = prsnl.position;
        const alreadyExists = this.configuredPositions().includes(position);

        if (!alreadyExists) {
          this.editableConfig.update(config => {
            if (!config) return config;
            const updated = { ...config, tabs: { ...config.tabs } };
            if (!updated.tabs['schedule']) {
              updated.tabs['schedule'] = { label: 'Schedule', positions: [position] };
            } else {
              const tab = { ...updated.tabs['schedule'], positions: [...updated.tabs['schedule'].positions, position] };
              updated.tabs['schedule'] = tab;
            }
            return updated;
          });
        }

        this.lookupResult.set({
          name: prsnl.nameFullFormatted,
          position,
          added: !alreadyExists,
          alreadyExists
        });

        this.selectedPersonnelId.set(0);
      } else {
        setTimeout(check, 200);
      }
    };
    setTimeout(check, 200);
  }

  save(): void {
    this.saving.set(true);
    const config = this.configService.configuration();
    const updated: OncSchedConfiguration = {
      ...config ?? { UPDT_DT_TM: '', APPOINTMENT_TYPES: [] },
      ACCESS_CONTROL: this.editableConfig() ?? undefined
    };

    this.configService.saveConfiguration(updated);
    this.saving.set(false);
    this.showStatus('Security settings saved.');
  }

  private showStatus(message: string): void {
    if (this.statusTimer) clearTimeout(this.statusTimer);
    this.statusMessage.set(message);
    this.statusTimer = setTimeout(() => this.statusMessage.set(null), 4000);
  }

  discard(): void {
    const config = this.configService.configuration()?.ACCESS_CONTROL;
    this.editableConfig.set(config ? JSON.parse(JSON.stringify(config)) : { superusers: [], tabs: {} });
  }
}
